1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Premium basics
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("single plain sword yields premium of 105 G (100 base + 5 fee)");
14	  it.todo("single plain amulet yields premium of 65 G");
15	  it.todo("single plain staff yields premium of 85 G");
16	  it.todo("single plain potion yields premium of 45 G");
17	
18	  // Multiple items
19	  it.todo("plain sword + plain amulet yields premium of 165 G (100+60+5)");
20	
21	  // Components
22	  it.todo("2 runes yield premium of 55 G (50 base + 5 fee)");
23	  it.todo("3 runes yield premium of 65 G (60 base block + 5 fee)");
24	  it.todo("4 runes yield premium of 105 G (4×25 + 5)");
25	  it.todo("7 runes yield premium of 180 G (175 + 5)");
26	  it.todo("2 runes + 1 moonstone yield premium of 80 G (no block, different types)");
27	  it.todo("3 runes + 3 moonstones yield premium of 125 G (two separate blocks)");
28	
29	  // Modifiers
30	  it.todo("cursed sword adds 50% surcharge of its base premium");
31	  it.todo("highly enchanted sword (level ≥ 5) adds 30% surcharge");
32	  it.todo("loyalty discount of 20% applies for ≥ 2 years customer");
33	  it.todo("first insurance surcharge of 10% applies to each item");
34	  it.todo("follow-up contract gives 15% discount on subsequent contracts");
35	
36	  // Modifier scope examples from spec
37	  it.todo("cursed sword + plain amulet: curse surcharge applies only to cursed item base");
38	
39	  // Rounding
40	  it.todo("premium calculations round up (MHPCO's favor)");
41	
42	  // Integration examples
43	  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
44	  it.todo("long-standing customer's 2nd contract with cursed sword (enchantment 7) → 160 G");
45	
46	  // Claims — basic
47	  it.todo("standard claim: regular sword, damage 500 → payout 400 (minus 100 deductible)");
48	  it.todo("standard claim on rune: insurance value 250, damage 200 → payout 100");
49	  it.todo("high enchantment ≥ 8: 50% reimbursement then deductible");
50	  it.todo("dragon material: full reimbursement minus deductible");
51	  it.todo("dragon material + enchantment 9: 50% rule wins, then deductible");
52	  it.todo("dragon-material enchantment 5: only dragon clause, full reimbursement minus deductible");
53	  it.todo("deductible applies per damaged item (multi-damage event)");
54	  it.todo("payout calculation rounds down (MHPCO's favor)");
55	
56	  // Multiple items of same type
57	  it.todo("two swords in policy, both damaged → each its own deductible");
58	  it.todo("damages contains more items of type than insured → error");
59	
60	  // Errors
61	  it.todo("unknown item type in quote → throws / non-zero exit");
62	  it.todo("claim references item not in policy → throws / non-zero exit");
63	  it.todo("claim with negative damage amount → throws / non-zero exit");
64	});
